// Deterministic Forecasting Engine
// Formula: Forecast = Baseline × Seasonality × Marketing Uplift × Price Impact × Channel Effects

const skus = $node['Fetch Active SKUs'].json;
const shopifyOrders = $node['Fetch Shopify History (6m)'].json;
const amazonOrders = $node['Fetch Amazon History (6m)'].json;

// Seasonality indices (UK patterns)
const SEASONALITY = {
  tea: { 1: 1.15, 2: 1.10, 3: 1.05, 4: 0.85, 5: 0.80, 6: 0.75, 7: 0.75, 8: 0.78, 9: 0.90, 10: 1.10, 11: 1.20, 12: 1.25 },
  drinks: { 1: 0.80, 2: 0.85, 3: 0.95, 4: 1.10, 5: 1.20, 6: 1.25, 7: 1.25, 8: 1.20, 9: 1.05, 10: 0.90, 11: 0.80, 12: 0.85 },
  health_products: { 1: 1.10, 2: 1.05, 3: 1.00, 4: 0.95, 5: 0.95, 6: 0.90, 7: 0.90, 8: 0.90, 9: 0.95, 10: 1.05, 11: 1.10, 12: 1.15 }
};

const AMBITIOUS_MULTIPLIER = 1.25;
const now = new Date();
const targetMonth = now.getMonth() + 2; // Next month
const targetYear = targetMonth > 12 ? now.getFullYear() + 1 : now.getFullYear();
const adjustedMonth = targetMonth > 12 ? targetMonth - 12 : targetMonth;
const monthStr = `${targetYear}-${String(adjustedMonth).padStart(2, '0')}`;

const forecasts = [];

// Process each SKU
for (const sku of (Array.isArray(skus) ? skus : [skus])) {
  const allOrders = [
    ...(Array.isArray(shopifyOrders) ? shopifyOrders : [shopifyOrders]).filter(o => o.sku_id === sku.sku_id),
    ...(Array.isArray(amazonOrders) ? amazonOrders : [amazonOrders]).filter(o => o.sku_id === sku.sku_id)
  ];

  // Calculate 8-week moving average baseline
  const recentOrders = allOrders.sort((a, b) => b.order_date?.localeCompare(a.order_date));
  const monthlyTotals = {};
  for (const order of recentOrders) {
    const m = order.order_date?.substring(0, 7);
    if (m) monthlyTotals[m] = (monthlyTotals[m] || 0) + (order.quantity || 0);
  }
  const monthValues = Object.values(monthlyTotals).slice(0, 2);
  const baseline = monthValues.length > 0 ? Math.round(monthValues.reduce((a, b) => a + b, 0) / monthValues.length) : 100;

  // Apply seasonality
  const cat = sku.category || 'drinks';
  const seasonality = SEASONALITY[cat]?.[adjustedMonth] || 1.0;

  // Marketing uplift (default 1.0 until ad data integrated)
  const marketingUplift = 1.0;

  // Price impact (default 1.0)
  const priceImpact = 1.0;

  // Channel effect (default 1.0)
  const channelEffect = 1.0;

  const forecastBaseline = Math.round(baseline * seasonality * marketingUplift * priceImpact * channelEffect);
  const forecastAmbitious = Math.round(forecastBaseline * AMBITIOUS_MULTIPLIER);

  forecasts.push({
    json: {
      sku_id: sku.sku_id,
      channel: sku.channel_primary || 'Both',
      month: monthStr,
      forecast_baseline: forecastBaseline,
      forecast_ambitious: forecastAmbitious,
      ad_spend_planned: 0,
      cac_planned: 0,
      version: 1,
      generated_at: new Date().toISOString()
    }
  });
}

return forecasts;

